import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  CardActions,
  Button,
  Chip,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  CircularProgress,
  Alert,
} from '@mui/material';
import {
  LocalHospital,
  People,
  AccessTime,
  MedicalServices,
} from '@mui/icons-material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Departments = () => {
  const navigate = useNavigate();
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchDepartments();
  }, []);

  const fetchDepartments = async () => {
    try {
      setLoading(true);
      const response = await axios.get('/api/departments');
      console.log('Departments data:', response.data);
      if (Array.isArray(response.data)) {
        setDepartments(response.data);
      } else {
        console.error('Invalid departments data:', response.data);
        setError('Invalid data received from server');
      }
    } catch (err) {
      console.error('Error fetching departments:', err);
      setError(err.response?.data?.message || 'Failed to fetch departments');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ mt: 4, mb: 4, display: 'flex', justifyContent: 'center' }}>
          <CircularProgress />
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography variant="h4" gutterBottom>
          Our Departments
        </Typography>
        <Typography variant="body1" color="text.secondary" paragraph>
          Explore our specialized medical departments and services
        </Typography>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      <Grid container spacing={3}>
        {departments.length === 0 ? (
          <Grid item xs={12}>
            <Alert severity="info">No departments available at the moment.</Alert>
          </Grid>
        ) : (
          departments.map((department) => (
            <Grid item xs={12} md={6} key={department._id}>
              <Card 
                elevation={2}
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  '&:hover': {
                    boxShadow: 6,
                    transform: 'translateY(-4px)',
                    transition: 'all 0.3s ease-in-out',
                  },
                }}
              >
                <CardContent sx={{ flexGrow: 1 }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                    <LocalHospital sx={{ fontSize: 40, mr: 2, color: 'primary.main' }} />
                    <Typography variant="h5" component="div">
                      {department.name}
                    </Typography>
                  </Box>
                  <Typography variant="body2" color="text.secondary" paragraph>
                    {department.description}
                  </Typography>
                  {department.services && department.services.length > 0 && (
                    <Box sx={{ mb: 2 }}>
                      <Typography variant="subtitle2" gutterBottom>
                        Services:
                      </Typography>
                      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                        {department.services.map((service, index) => (
                          <Chip
                            key={index}
                            label={service}
                            size="small"
                            color="primary"
                            variant="outlined"
                          />
                        ))}
                      </Box>
                    </Box>
                  )}
                  {department.facilities && department.facilities.length > 0 && (
                    <Box sx={{ mb: 2 }}>
                      <Typography variant="subtitle2" gutterBottom>
                        Facilities:
                      </Typography>
                      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                        {department.facilities.map((facility, index) => (
                          <Chip
                            key={index}
                            label={facility}
                            size="small"
                            color="secondary"
                            variant="outlined"
                          />
                        ))}
                      </Box>
                    </Box>
                  )}
                  {department.workingHours && (
                    <Box>
                      <Typography variant="subtitle2" gutterBottom>
                        Working Hours:
                      </Typography>
                      <List dense>
                        {Object.entries(department.workingHours).map(([day, hours]) => (
                          <ListItem key={day}>
                            <ListItemIcon>
                              <AccessTime fontSize="small" />
                            </ListItemIcon>
                            <ListItemText
                              primary={day.charAt(0).toUpperCase() + day.slice(1)}
                              secondary={hours}
                            />
                          </ListItem>
                        ))}
                      </List>
                    </Box>
                  )}
                </CardContent>
                <Divider />
                <CardActions>
                  <Button
                    size="small"
                    color="primary"
                    fullWidth
                    variant="contained"
                    onClick={() => navigate('/doctors', { state: { department: department._id } })}
                  >
                    View Doctors
                  </Button>
                </CardActions>
              </Card>
            </Grid>
          ))
        )}
      </Grid>
    </Container>
  );
};

export default Departments;
